import{_ as a,c as e,o as m,d as t}from"./plugin-vue_export-helper.23b45acd.js";const k='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 29-30","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 29-30","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-01-24T00:00:00.000Z"},"relativePath":"texts/shiva-sutra-vimarshini/3/29-30.md","lastUpdated":1626206162630}',i={},r=t('<div class="stanza"><a href="#s3.29" id="s3.29" class="num">3.29</a><div class="sans"><p>\u092F\u0925\u094B\u0915\u094D\u0924\u0928\u0940\u0924\u094D\u092F\u093E \u0936\u093F\u0935\u0924\u0941\u0932\u094D\u092F\u0924\u092F\u093E \u0928\u093F\u0924\u094D\u092F\u092E\u0947\u0935\u0902 \u0935\u094D\u0930\u0924\u091C\u092A\u091A\u0930\u094D\u092F\u093E\u0928\u093F\u0937\u094D\u0920\u0924\u094D\u0935\u093E\u0928\u094D\u0928\u093F\u091C\u0936\u0915\u094D\u0924\u093F\u091A\u0915\u094D\u0930\u093E\u0930\u0942\u0922\u0903 \u0938 \u090F\u0935 \u0924\u0924\u094D\u0924\u094D\u0935\u0924 \u0909\u092A\u0926\u0947\u0936\u094D\u092F\u093E\u0928\u093E\u0902 \u092A\u094D\u0930\u0924\u093F\u092C\u094B\u0927\u0915 \u0907\u0924\u094D\u092F\u093E\u0939\u2014</p><blockquote><p><strong>\u092F\u094B\u093D\u0935\u093F\u092A\u0938\u094D\u0925\u094B \u091C\u094D\u091E\u093E\u0939\u0947\u0924\u0941\u0936\u094D\u091A\u0965\u0968\u096F\u0965</strong></p></blockquote><p>\u0905\u0935\u0940\u0928\u094D \u092A\u0936\u0942\u0928\u094D \u092A\u093E\u0924\u0940\u0924\u094D\u092F\u0935\u093F\u092A\u0902 \u0915\u0935\u0930\u094D\u0917\u093E\u0926\u093F\u0937\u0941 \u092E\u093E\u0939\u0947\u0936\u094D\u0935\u0930\u094D\u092F\u093E\u0926\u094D\u092F\u093E\u0903 \u092A\u0936\u0941\u092E\u093E\u0924\u0930\u0903 (\u0969-\u0967\u096F) \u0907\u0924\u094D\u092F\u092D\u093F\u0939\u093F\u0924\u0926\u0943\u0936\u093E \u092E\u093E\u0939\u0947\u0936\u094D\u0935\u0930\u094D\u092F\u093E\u0926\u093F\u0936\u0915\u094D\u0924\u093F\u091A\u0915\u094D\u0930\u0902 \u0924\u0924\u094D\u0930 \u0924\u093F\u0937\u094D\u0920\u0924\u093F \u0935\u093F\u0926\u093F\u0924\u0938\u094D\u0935\u092E\u093E\u0939\u093E\u0924\u094D\u092E\u094D\u092F\u0924\u094D\u0935\u093E\u0924\u094D\u092A\u094D\u0930\u092D\u0941\u0924\u094D\u0935\u0947\u0928 \u092F\u0903 \u092A\u094D\u0930\u0924\u092A\u0924\u093F \u0938 \u091C\u094D\u091E\u093E\u0939\u0947\u0924\u0941\u0930\u094D\u091C\u093E\u0928\u093E\u0924\u0940\u0924\u093F \u091C\u094D\u091E\u093E \u091C\u094D\u091E\u093E\u0928\u0936\u0915\u094D\u0924\u093F\u0938\u094D\u0924\u0938\u094D\u092F\u093E \u0939\u0947\u0924\u0941\u0930\u0941\u092A\u0926\u0947\u0936\u094D\u092F\u093E\u0928\u094D \u091C\u094D\u091E\u093E\u0928\u0936\u0915\u094D\u0924\u094D\u092F\u093E \u092A\u094D\u0930\u0924\u093F\u092C\u094B\u0927\u092F\u093F\u0924\u0941\u0902 \u0915\u094D\u0937\u092E\u0903\u0964 \u0905\u0928\u094D\u092F\u0938\u094D\u0924\u0941 \u0936\u0915\u094D\u0924\u093F\u091A\u0915\u094D\u0930\u092A\u0930\u0924\u0928\u094D\u0924\u094D\u0930\u0940\u0915\u0943\u0924\u0924\u094D\u0935\u093E\u0924\u094D\u0938\u094D\u0935\u093E\u0924\u094D\u092E\u0928\u094D\u092F\u092A\u094D\u0930\u092D\u0935\u093F\u0937\u094D\u0923\u0941\u0903 \u0915\u0925\u092E\u0928\u094D\u092F\u093E\u0928\u094D\u092A\u094D\u0930\u092C\u094B\u0927\u092F\u0947\u0924\u094D\u0964 \u092F\u091A\u094D\u091B\u092C\u094D\u0926\u093E\u092A\u0947\u0915\u094D\u0937\u092F\u093E \u0938\u0942\u0924\u094D\u0930\u0947\u093D\u0924\u094D\u0930 \u0924\u091A\u094D\u091B\u092C\u094D\u0926\u094B\u093D\u0927\u094D\u092F\u093E\u0939\u093E\u0930\u094D\u092F\u0903\u0964 \u091A \u0936\u092C\u094D\u0926\u094B \u0939\u094D\u092F\u0930\u094D\u0925\u0947\u0964 \u092F\u094B\u093D\u092F\u092E\u0935\u093F\u092A\u0938\u094D\u0925\u0903 \u0938 \u092F\u0938\u094D\u092E\u093E\u091C\u094D\u091C\u094D\u091E\u093E\u0928\u092A\u094D\u0930\u092C\u094B\u0927\u0928\u0939\u0947\u0924\u0941\u0938\u094D\u0924\u0938\u094D\u092E\u093E\u0926\u094D\u092F\u0941\u0915\u094D\u0924\u092E\u0941\u0915\u094D\u0924\u0902 \u0926\u093E\u0928\u092E\u093E\u0924\u094D\u092E\u091C\u094D\u091E\u093E\u0928\u092E\u094D (\u0969-\u0968\u096E) \u0907\u0924\u093F\u0964</p><p>\u0905\u0928\u094D\u092F\u0947 \u0924\u0941 \u0905\u0915\u094D\u0937\u0930\u0938\u093E\u0930\u0942\u092A\u094D\u092F\u093E\u0924\u094D\u092A\u094D\u0930\u092C\u094D\u0930\u0942\u092F\u093E\u0926\u093F\u0924\u093F \u0928\u093F\u0930\u0941\u0915\u094D\u0924\u0938\u094D\u0925\u093F\u0924\u094D\u092F\u093E \u092F\u094B \u0907\u0924\u093F \u092F\u094B\u0917\u0940\u0928\u094D\u0926\u094D\u0930\u094B \u0935\u093F \u0907\u0924\u093F \u0935\u093F\u091C\u094D\u091E\u093E\u0928\u0902 \u092A \u0907\u0924\u093F \u092A\u0926\u0902 \u0938\u094D\u0925 \u0907\u0924\u093F \u092A\u0926\u0938\u094D\u0925 \u0907\u0924\u094D\u092F\u0938\u094D\u092F\u093E\u0928\u094D\u0924\u094D\u092F\u092E\u0915\u094D\u0937\u0930\u092E\u094D\u0964 \u091C\u094D\u091E \u0907\u0924\u093F \u091C\u094D\u091E\u093E\u0924\u093E \u0939\u0947 \u0907\u0924\u093F \u0939\u0947\u092F\u0938\u094D\u0924\u0941 \u0907\u0924\u093F \u0924\u0941\u091A\u094D\u091B\u0924\u093E \u0935\u093F\u0938\u0930\u094D\u091C\u0928\u0940\u092F\u0947\u0928 \u0935\u093F\u0938\u0930\u094D\u0917\u0936\u0915\u094D\u0924\u093F\u0936\u094D\u091A\u0915\u093E\u0930\u0947\u0923\u093E\u0928\u0941\u0915\u094D\u0924\u0938\u092E\u0941\u091A\u094D\u091A\u092F\u093E\u0930\u094D\u0925\u0947\u0928 \u0915\u0930\u094D\u0924\u093E \u092A\u0930\u093E\u092E\u0943\u0936\u094D\u092F\u0924 \u0907\u0924\u094D\u092F\u093E\u0936\u094D\u0930\u093F\u0924\u094D\u092F \u092F\u094B \u092F\u094B\u0917\u0940\u0928\u094D\u0926\u094D\u0930\u094B \u0935\u093F\u092E\u0930\u094D\u0936\u0936\u0915\u094D\u0924\u094D\u092F\u093E \u0938\u094D\u0935\u0930\u0942\u092A\u093E\u0924\u094D\u092E\u0935\u093F\u091C\u094D\u091E\u093E\u0928\u092A\u0926\u0938\u094D\u0925\u0903 \u0938 \u091C\u094D\u091E\u093E\u0924\u093E \u0915\u0930\u094D\u0924\u093E \u091A\u093E\u0935\u0917\u0928\u094D\u0924\u0935\u094D\u092F\u0938\u094D\u0924\u0926\u093E \u091A\u093E\u0938\u094D\u092F \u0939\u0947\u092F\u0924\u093E\u0902 \u0924\u0941\u091A\u094D\u091B\u0924\u093E\u0902 \u0928\u093F\u0903\u0938\u093E\u0930\u0924\u093E\u0902 \u0928 \u0924\u0942\u092A\u093E\u0926\u0947\u092F\u0924\u093E\u092E\u093E\u0938\u093E\u0926\u092F\u0924\u0940\u0924\u093F \u0935\u094D\u092F\u093E\u091A\u0915\u094D\u0937\u0924\u0947\u0964 \u090F\u0924\u091A\u094D\u091A \u0928 \u0928\u0903 \u092A\u094D\u0930\u0924\u093F\u092D\u093E\u0924\u093F \u092A\u0926\u093E\u0930\u094D\u0925\u0938\u0919\u094D\u0917\u0924\u0947\u0930\u094D\u0928\u093E\u0924\u093F\u091A\u093E\u0930\u0941\u0924\u094D\u0935\u093E\u0924\u094D\u092A\u094D\u0930\u0924\u093F\u0938\u0942\u0924\u094D\u0930\u0902 \u091A\u0947\u0926\u0943\u0936\u0935\u094D\u092F\u093E\u0916\u094D\u092F\u093E\u0915\u094D\u0930\u092E\u0938\u094D\u092F \u0938\u0939\u0938\u094D\u0930\u0936\u094B \u0926\u0930\u094D\u0936\u092F\u093F\u0924\u0941\u0902 \u0936\u0915\u094D\u092F\u0924\u094D\u0935\u093E\u0924\u094D\u0965\u0968\u096F\u0965</p></div><hr><div class="trans"><p>Yathoktan\u012Bty\u0101 \u015Bivatulyatay\u0101 nityameva\u1E41 vratajapacary\u0101ni\u1E63\u1E6Dhatv\u0101nnija\u015Bakticakr\u0101r\u016B\u1E0Dha\u1E25 sa eva tattvata upade\u015By\u0101n\u0101\u1E41 pratibodhaka ity\u0101ha\u2014</p><blockquote><p><strong>Yo&#39;vipastho j\xF1\u0101hetu\u015Bca||29||</strong></p></blockquote><p>Av\u012Bn pa\u015B\u016Bn p\u0101t\u012Btyavipa\u1E41 kavarg\u0101di\u1E63u m\u0101he\u015Bvary\u0101dy\u0101\u1E25 pa\u015Bum\u0101tara\u1E25 (3-19) ityabhihitad\u1E5B\u015B\u0101 m\u0101he\u015Bvary\u0101di\u015Bakticakra\u1E41 tatra ti\u1E63\u1E6Dhati viditasvam\u0101h\u0101tmyatv\u0101tprabhutvena ya\u1E25 pratapati sa j\xF1\u0101heturj\u0101n\u0101t\u012Bti j\xF1\u0101 j\xF1\u0101na\u015Baktistasy\u0101 heturupade\u015By\u0101n j\xF1\u0101na\u015Bakty\u0101 pratibodhayitu\u1E41 k\u1E63ama\u1E25| Anyastu \u015Bakticakraparatantr\u012Bk\u1E5Btatv\u0101tsv\u0101tmanyaprabhavi\u1E63\u1E47u\u1E25 kathamany\u0101nprabodhayet| Yacchabd\u0101pek\u1E63ay\u0101 s\u016Btre&#39;tra tacchabdo&#39;dhy\u0101h\u0101rya\u1E25| Ca \u015Babdo hyarthe| Yo&#39;yamavipastha\u1E25 sa yasm\u0101jj\xF1\u0101naprabodhanahetustasm\u0101dyuktamukta\u1E41 d\u0101nam\u0101tmaj\xF1\u0101nam (3-28) iti|</p><p>Anye tu ak\u1E63aras\u0101r\u016Bpy\u0101tprabr\u016By\u0101diti niruktasthity\u0101 yo iti yog\u012Bndro vi iti vij\xF1\u0101na\u1E41 pa iti pada\u1E41 stha iti padastha ityasy\u0101ntyamak\u1E63aram| J\xF1a iti j\xF1\u0101t\u0101 he iti heyastu iti tucchat\u0101 visarjan\u012Byena visarga\u015Bakti\u015Bcak\u0101re\u1E47\u0101nuktasamuccay\u0101rthena kart\u0101 par\u0101m\u1E5B\u015Byata ity\u0101\u015Britya yo yog\u012Bndro vimar\u015Ba\u015Bakty\u0101 svar\u016Bp\u0101tmavij\xF1\u0101napadastha\u1E25 sa j\xF1\u0101t\u0101 kart\u0101 c\u0101vagantavyastad\u0101 c\u0101sya heyat\u0101\u1E41 tucchat\u0101\u1E41 ni\u1E25s\u0101rat\u0101\u1E41 na t\u016Bp\u0101deyat\u0101m\u0101s\u0101dayat\u012Bti vy\u0101cak\u1E63ate| Etacca na na\u1E25 pratibh\u0101ti pad\u0101rthasa\u1E45gatern\u0101tic\u0101rutv\u0101tpratis\u016Btra\u1E41 ced\u1E5B\u015Bavy\u0101khy\u0101kramasya sahasra\u015Bo dar\u015Bayitu\u1E41 \u015Bakyatv\u0101t||29||</p></div><hr><p>\u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0442\u043E\u043C\u0443, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E <em>(yath\u0101-ukta-n\u012Bty\u0101)</em>, \u043E\u043D \u0432\u0441\u0435\u0433\u0434\u0430 \u0440\u0430\u0432\u0435\u043D <em>(tulyatay\u0101 nityam)</em> \u015Aiva <em>(\u015Biva)</em>. [\u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E,] \u043E\u043D \u043E\u0434\u0438\u043D <em>(sa\u1E25 eva)</em> \u0432 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 [\u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C] <em>(tattvatas)</em> \u0443\u0447\u0438\u0442\u0435\u043B\u0435\u043C --\u0442\u0435\u043C, \u043A\u0442\u043E \u0437\u0430\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0432\u0430\u0441 \u043E\u0441\u043E\u0437\u043D\u0430\u0442\u044C \u0432\u0430\u0448\u0443 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443-- <em>(pratibodhaka\u1E25)</em> \u0443\u0447\u0435\u043D\u0438\u043A\u043E\u0432 <em>(upade\u015By\u0101n\u0101m)</em>, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E, \u0431\u0443\u0434\u0443\u0447\u0438 \u043F\u0440\u0438\u0432\u0435\u0440\u0436\u0435\u043D\u043D\u044B\u043C <em>(ni\u1E63\u1E6Dhatv\u0101t)</em> vrata, japa \u0438 cary\u0101, \u0438\u043B\u0438 \u0440\u0435\u043B\u0438\u0433\u0438\u043E\u0437\u043D\u044B\u043C \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0430\u043C <em>(vrata-japa-cary\u0101)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em>, \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433 [\u043E\u0432\u043B\u0430\u0434\u0435\u043D\u0438\u044F] <em>(\u0101r\u016B\u1E0Dha\u1E25)</em> \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(nija)</em> \u0433\u0440\u0443\u043F\u043F\u043E\u0439 <em>(cakra)</em> \u0441\u0438\u043B <em>(\u015Bakti)</em>. [\u015Aiva] \u0441\u043A\u0430\u0437\u0430\u043B <em>(\u0101ha)</em> \u0442\u0430\u043A <em>(iti)</em> [\u0432 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435]\u2014</p><blockquote><p><strong>\u041E\u043D, \u043A\u0442\u043E <em>(ya\u1E25)</em> \u0443\u043A\u043E\u0440\u0435\u043D\u0435\u043D [\u0432 \u0433\u0440\u0443\u043F\u043F\u0435 \u0441\u0438\u043B, \u0438\u043B\u0438 \u015Aakticakra] <em>(avipastha\u1E25)</em>, \u0432\u043E\u0438\u0441\u0442\u0438\u043D\u0443 [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] <em>(ca)</em> \u043E\u0440\u0443\u0434\u0438\u0435\u043C <em>(hetu\u1E25)</em> \u043C\u0443\u0434\u0440\u043E\u0441\u0442\u0438 <em>(j\xF1\u0101)</em>||29||</strong></p></blockquote><p>[\u0422\u0435\u0440\u043C\u0438\u043D &quot;avipastha\u1E25&quot; --\u0443\u043A\u043E\u0440\u0435\u043D\u0435\u043D\u043D\u044B\u0439/\u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u043D\u044B\u0439 (\u0432 \u0433\u0440\u0443\u043F\u043F\u0435 \u0441\u0438\u043B, \u0438\u043B\u0438 \u015Aakticakra)-- \u0434\u043E\u043B\u0436\u0435\u043D \u0442\u043E\u043B\u043A\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C:] avipa <em>(avipam)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &quot;\u0442\u043E\u0442, \u043A\u0442\u043E \u0437\u0430\u0449\u0438\u0449\u0430\u0435\u0442 <em>(p\u0101ti)</em> avi-s <em>(av\u012Bn)</em>, [\u0438\u043B\u0438] \u0436\u0438\u0432\u043E\u0442\u043D\u044B\u0445 --\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432-- <em>(pa\u015B\u016Bn)</em>&quot;, [\u0442\u043E \u0435\u0441\u0442\u044C,] \u0433\u0440\u0443\u043F\u043F\u0430 <em>(cakram)</em> \u0441\u0438\u043B <em>(\u015Bakti)</em>, [\u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0430\u044F \u0438\u0437] M\u0101he\u015Bvar\u012B <em>(m\u0101he\u015Bvar\u012B)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0442\u043E\u0447\u043A\u0435 \u0437\u0440\u0435\u043D\u0438\u044F <em>(d\u1E5B\u015B\u0101)</em>, \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0435\u043D\u043D\u043E\u0439 <em>(abhihita)</em> [\u0432] (III, 19) [\u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F]: &quot;M\u0101he\u015Bvar\u012B <em>(m\u0101he\u015Bvar\u012B)</em> \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u0431\u043E\u0433\u0438\u043D\u0438 <em>(\u0101dy\u0101\u1E25)</em>, [\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0438\u043C\u0435\u044E\u0442 \u0441\u0432\u043E\u044E \u0441\u0444\u0435\u0440\u0443 \u0432\u043B\u0438\u044F\u043D\u0438\u044F] \u0432 &#39;ka&#39; <em>(ka)</em> \u0433\u0440\u0443\u043F\u043F\u0435 <em>(varga)</em>, \u0438 \u0442.\u0434. <em>(\u0101di\u1E63u)</em>, [\u0438 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F] \u043C\u0430\u0442\u0435\u0440\u044F\u043C\u0438 <em>(m\u0101tara\u1E25)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432 <em>(pa\u015Bu)</em>, [\u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F \u0435\u0433\u043E \u0433\u043B\u0430\u0432\u043D\u044B\u043C\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0430\u043C\u0438]. <em>(3-19 iti)</em>&quot;. [\u0422\u0435\u0440\u043C\u0438\u043D &quot;stha\u1E25&quot; \u0432 &quot;avipastha\u1E25&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442, \u0447\u0442\u043E] \u044D\u0442\u043E\u0442 [\u0432\u0435\u043B\u0438\u043A\u0438\u0439 Yog\u012B] <em>(ya\u1E25)</em> \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 <em>(ti\u1E63\u1E6Dhati)</em> \u0442\u0430\u043C --\u0432 \u0433\u0440\u0443\u043F\u043F\u0435 \u0441\u0438\u043B, \u0438\u043B\u0438 \u015Aakticakra-- <em>(tatra)</em> [\u0438] \u0441\u0438\u044F\u0435\u0442 <em>(pratapati)</em> \u043A\u0430\u043A \u043F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u044C [\u0442\u0430\u043A\u0438\u0445 \u0441\u0438\u043B] <em>(prabhutvena)</em>, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D \u0437\u043D\u0430\u0435\u0442 \u0441\u0432\u043E\u0435 \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0438\u043B\u0438 \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435 <em>(vidita-sva-m\u0101h\u0101tmyatv\u0101t)</em> --\u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0435\u0433\u043E \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0438\u043B\u0438 \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E--. \u041E\u043D <em>(sa\u1E25)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] &quot;j\xF1\u0101hetu\u1E25&quot;, [\u0438\u043B\u0438] &quot;\u043E\u0440\u0443\u0434\u0438\u0435\u043C \u043C\u0443\u0434\u0440\u043E\u0441\u0442\u0438&quot; <em>(j\xF1\u0101hetu\u1E25)</em> [\u0438\u0437-\u0437\u0430 \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u043E\u043D \u2014] \u043E\u0440\u0443\u0434\u0438\u0435/\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E, \u0438\u043B\u0438 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A <em>(hetu\u1E25)</em> \u044D\u0442\u043E\u0433\u043E <em>(tasy\u0101)</em> &quot;j\xF1\u0101&quot; <em>(j\xF1\u0101)</em> \u2014&quot;\u0442\u043E\u0442, \u043A\u0442\u043E \u0437\u043D\u0430\u0435\u0442 <em>(j\u0101n\u0101ti iti)</em>&quot;\u2014, \u0442.\u0435. J\xF1\u0101na\u015Bakti, \u0438\u043B\u0438 \u0421\u0438\u043B\u0430 \u0417\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101na-\u015Bakti\u1E25)</em>. [\u041F\u043E \u044D\u0442\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435,] \u043E\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u0434\u0445\u043E\u0434\u044F\u0449\u0438\u043C <em>(k\u1E63ama\u1E25)</em> \u0434\u043B\u044F \u043E\u0431\u0443\u0447\u0435\u043D\u0438\u044F \u0438 \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u044F <em>(pratibodhayitu)</em> [\u0441\u0432\u043E\u0438\u0445] \u0443\u0447\u0435\u043D\u0438\u043A\u043E\u0432 <em>(upade\u015By\u0101n)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0421\u0438\u043B\u044B \u0417\u043D\u0430\u043D\u0438\u044F --\u0442.\u0435. \u0447\u0435\u0440\u0435\u0437 \u0435\u0433\u043E \u043C\u0443\u0434\u0440\u043E\u0441\u0442\u044C-- <em>(j\xF1\u0101na\u015Bakty\u0101)</em>|</p><p>\u041E\u0434\u043D\u0430\u043A\u043E <em>(tu)</em>, \u0434\u0440\u0443\u0433\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E, [\u043F\u043E\u043C\u0438\u043C\u043E \u0442\u0430\u043A\u043E\u0433\u043E \u0440\u043E\u0434\u0430 Yog\u012B] <em>(anya\u1E25)</em>, \u0431\u0443\u0434\u0443\u0447\u0438 \u043F\u043E\u0434\u0447\u0438\u043D\u0435\u043D\u043D\u044B\u043C <em>(paratantr\u012Bk\u1E5Btatv\u0101t)</em> \u0433\u0440\u0443\u043F\u043F\u0435 <em>(cakra)</em> \u0441\u0438\u043B <em>(\u015Bakti)</em>, \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u0435\u043C <em>(aprabhavi\u1E63\u1E47u\u1E25)</em> \u0441\u0430\u043C\u043E\u0433\u043E \u0441\u0435\u0431\u044F <em>(sva-\u0101tmani)</em>. \u041A\u0430\u043A <em>(katham)</em> [\u0442\u043E\u0433\u0434\u0430] \u043E\u043D \u043C\u043E\u0433 \u0431\u044B \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0430\u0442\u044C <em>(prabodhayet)</em> \u0434\u0440\u0443\u0433\u0438\u0445 <em>(any\u0101n)</em>?|</p><p>\u041E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E <em>(apek\u1E63ay\u0101)</em> \u0441\u043B\u043E\u0432\u0430 <em>(\u015Babda)</em> &quot;ya\u1E25&quot; --\u043A\u0442\u043E-- <em>(yad)</em>, [\u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u043D\u043E\u0433\u043E] \u0432 \u044D\u0442\u043E\u043C <em>(atra)</em> \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435 <em>(s\u016Btre)</em>, \u043E\u043D\u043E \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u0434\u043E\u043F\u043E\u043B\u043D\u0435\u043D\u043E [\u0434\u043B\u044F \u043F\u043E\u043B\u043D\u043E\u0442\u044B \u0441\u043C\u044B\u0441\u043B\u0430] <em>(adhy\u0101h\u0101rya\u1E25)</em> \u0441\u043B\u043E\u0432\u043E\u043C <em>(\u015Babda\u1E25)</em> &quot;sa\u1E25&quot; --\u043E\u043D-- <em>(tad)</em> --\u0432 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0435 \u043F\u043E\u043B\u0443\u0447\u0438\u043B\u043E\u0441\u044C &quot;\u043E\u043D, \u043A\u0442\u043E&quot;--|</p><p>\u0421\u043B\u043E\u0432\u043E <em>(\u015Babda\u1E25)</em> &quot;ca&quot; <em>(ca)</em> [\u0431\u044B\u043B\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u043E] \u0432 \u0441\u043C\u044B\u0441\u043B\u0435 <em>(arthe)</em> &quot;hi&quot; --\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E, \u043A\u043E\u043D\u0435\u0447\u043D\u043E \u0438 \u0442.\u0434.-- <em>(hi)</em>|</p><p>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 <em>(yasm\u0101t)</em> \u043E\u043D <em>(sa\u1E25)</em> \u2014\u0442.\u0435. \u044D\u0442\u043E\u0442 [Yog\u012B] <em>(ayam)</em>, \u0443\u043A\u043E\u0440\u0435\u043D\u0435\u043D\u043D\u044B\u0439 [\u0432 \u0433\u0440\u0443\u043F\u043F\u0435 \u0441\u0438\u043B, \u0438\u043B\u0438 \u015Aakticakra] <em>(avipastha\u1E25)</em>\u2014 [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C/\u043E\u0440\u0443\u0434\u0438\u0435\u043C <em>(hetu\u1E25)</em> \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u044F <em>(prabodhana)</em> \u0437\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101na)</em>, \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(tasm\u0101t)</em> \u0431\u044B\u043B\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(yuktam uktam)</em>: &quot;\u0417\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101nam)</em> \u0421\u0430\u043C\u043E\u0441\u0442\u0438 <em>(\u0101tma)</em> [\u0435\u0441\u0442\u044C \u0435\u0433\u043E] \u0434\u0430\u0440 <em>(d\u0101nam)</em> [\u0432\u0441\u0435\u043C \u043D\u0430\u043C]. (III, 28) [\u0434\u0430\u043D\u043D\u043E\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F] <em>(3-28 iti)</em>&quot;|</p><p>\u041E\u0434\u043D\u0430\u043A\u043E <em>(tu)</em>, \u0434\u0440\u0443\u0433\u0438\u0435 [\u0430\u0432\u0442\u043E\u0440\u044B] <em>(anye)</em>, \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0449\u0438\u0435 \u0442\u043E\u0447\u043A\u0443 \u0437\u0440\u0435\u043D\u0438\u044F <em>(sthity\u0101)</em> nirukta --\u0442\u0438\u043F \u0442\u043E\u043B\u043A\u043E\u0432\u0430\u043D\u0438\u044F \u0438 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u044F \u0441\u043B\u043E\u0432-- <em>(nirukta)</em>, [\u0431\u0430\u0437\u0438\u0440\u0443\u044E\u0449\u0443\u044E\u0441\u044F \u043D\u0430 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0435] &quot;\u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u043F\u043E\u0434\u043E\u0431\u0438\u0435\u043C <em>(s\u0101r\u016Bpy\u0101t)</em> \u0441\u043B\u043E\u0433\u043E\u0432 <em>(ak\u1E63ara)</em> \u044D\u0442\u043E \u043C\u043E\u0436\u043D\u043E \u0431\u044B\u043B\u043E \u0431\u044B \u0432\u044B\u0440\u0430\u0437\u0438\u0442\u044C <em>(prabr\u016By\u0101t)</em>&quot; --\u0442.\u0435. \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u043F\u043E\u0434\u043E\u0431\u0438\u0435\u043C \u0441\u043B\u043E\u0433\u043E\u0432 \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u044B\u0439 \u0442\u0435\u0440\u043C\u0438\u043D \u0432\u044B\u0440\u0430\u0436\u0430\u0435\u0442 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u043E \u0438\u0437 \u0441\u043B\u043E\u0432, \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u0445 \u0441 \u0435\u0433\u043E \u0441\u043B\u043E\u0433\u0430\u043C\u0438--, [\u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u044E\u0442, \u0447\u0442\u043E]: &quot;yo&quot; <em>(yo iti)</em> [\u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043D\u0430] yog\u012Bndra \u2014\u043F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u044F \u0441\u0440\u0435\u0434\u0438 Yog\u012B-s\u2014 <em>(yogi-indra\u1E25)</em>, &quot;vi&quot; <em>(vi iti)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] vij\xF1\u0101na \u2014\u043E\u0441\u043E\u0431\u043E\u0435 \u0437\u043D\u0430\u043D\u0438\u0435\u2014 <em>(vij\xF1\u0101nam)</em>, &quot;pa&quot; <em>(pa iti)</em> [\u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u043E] pada \u2014\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438\u2014 <em>(padam)</em>, [\u0438] &quot;stha\u1E25&quot; --\u0443\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u043D\u044B\u0439-- <em>(stha\u1E25 iti)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0438\u043C <em>(antyam)</em> \u0441\u043B\u043E\u0433\u043E\u043C <em>(ak\u1E63aram)</em> \u044D\u0442\u043E\u0433\u043E [\u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u044F] --\u0442.\u0435. Yo&#39;vipastha\u1E25 \u0432 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435--, [\u0444\u043E\u0440\u043C\u0438\u0440\u0443\u0435\u0442 \u043D\u0430\u0440\u044F\u0434\u0443 \u0441&quot;pada&quot;, \u0442\u0435\u0440\u043C\u0438\u043D] &quot;padastha\u1E25&quot; \u2014\u0443\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u043D\u044B\u0439/\u0443\u043A\u043E\u0440\u0435\u043D\u0435\u043D\u043D\u044B\u0439 \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438\u2014 <em>(padastha\u1E25 iti)</em>|</p><p>&quot;J\xF1a&quot; <em>(j\xF1a iti)</em> [\u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043D\u0430] j\xF1\u0101t\u0101 \u2014\u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0439\u2014 <em>(j\xF1\u0101t\u0101)</em>, &quot;he&quot; <em>(he iti)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] heya \u2014\u043E\u0442\u0442\u043E\u0440\u0433\u043D\u0443\u0442\u044B\u0439\u2014 <em>(heya\u1E25)</em>, &quot;tu&quot; <em>(tu iti)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] tucchat\u0101 \u2014\u0431\u0435\u0441\u043F\u043E\u043B\u0435\u0437\u043D\u043E\u0441\u0442\u044C\u2014 <em>(turya)</em>, [\u0438] \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C Visarga --&quot;\u1E25&quot; \u0432 \u043A\u043E\u043D\u0446\u0435 hetu\u1E25 \u0432 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435-- <em>(visarjan\u012Byena)</em> [\u0431\u0443\u0434\u0435\u0442 \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0435\u043D\u0430] \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0430\u044F \u0441\u0438\u043B\u0430 <em>(visarga-\u015Bakti\u1E25)</em>. \u0421\u043B\u043E\u0432\u043E\u043C <em>(k\u0101re\u1E47a)</em> &quot;ca&quot; <em>(ca)</em>, \u043D\u0435 \u0432\u044B\u0440\u0430\u0436\u0430\u044E\u0449\u0438\u043C [\u0437\u0434\u0435\u0441\u044C] <em>(anukta)</em> \u0441\u043C\u044B\u0441\u043B \u0432 \u0441\u043E\u0441\u043B\u0430\u0433\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u043C \u043D\u0430\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u0438 <em>(samuccaya-arthena)</em> --\u0447\u0430\u0441\u0442\u0438\u0446\u0443 &quot;ca&quot; \u043D\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C \u0437\u0434\u0435\u0441\u044C \u043A\u0430\u043A \u043E\u0431\u044B\u0447\u043D\u043E, \u0442.\u0435. \u043A\u0430\u043A \u043F\u0440\u043E\u0441\u0442\u043E\u0439 \u0441\u043E\u044E\u0437 &quot;\u0438&quot;--, \u0443\u043A\u0430\u0437\u0430\u043D <em>(par\u0101m\u1E5B\u015Byate)</em> \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0439, \u0438\u043B\u0438 \u0434\u0435\u043B\u0430\u0442\u0435\u043B\u044C <em>(kart\u0101)</em>. \u0418\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044F <em>(iti \u0101\u015Britya)</em> [\u0442\u0430\u043A\u043E\u0439 \u043C\u0435\u0442\u043E\u0434 \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0430\u0446\u0438\u0438, \u044D\u0442\u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u0430\u0432\u0442\u043E\u0440\u044B] \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u044E\u0442 <em>(vy\u0101cak\u1E63ate)</em> [\u0430\u0444\u043E\u0440\u0438\u0437\u043C \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C:]</p><p>&quot;\u0422\u043E\u0442, \u043A\u0442\u043E <em>(ya\u1E25)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u0435\u043C \u0441\u0440\u0435\u0434\u0438 Yog\u012B-s <em>(yogi-indra\u1E25)</em>, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0441\u0438\u043B\u044B <em>(\u015Bakty\u0101)</em> [\u042F-]\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(vimar\u015Ba)</em>, \u0443\u043A\u043E\u0440\u0435\u043D\u044F\u0435\u0442\u0441\u044F <em>(stha\u1E25)</em> \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 <em>(pada)</em> \u043E\u0441\u043E\u0431\u043E\u0433\u043E \u0437\u043D\u0430\u043D\u0438\u044F <em>(vij\xF1\u0101na)</em> \u043E \u043F\u0440\u0438\u0440\u043E\u0434\u0435 <em>(\u0101tma)</em> \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u0421\u0430\u043C\u043E\u0441\u0442\u0438 <em>(sva-r\u016Bpa)</em>. \u041E\u043D <em>(sa\u1E25)</em> \u0434\u043E\u043B\u0436\u0435\u043D \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0442\u044C\u0441\u044F \u043A\u0430\u043A <em>(avagantavya\u1E25)</em> \u0437\u043D\u0430\u044E\u0449\u0438\u0439 <em>(j\xF1\u0101t\u0101)</em> \u0438 <em>(ca)</em> \u0434\u0435\u043B\u0430\u0442\u0435\u043B\u044C <em>(kart\u0101)</em>. \u0412 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 <em>(tad\u0101 ca)</em>, \u043E\u043D \u043E\u0442\u0432\u0435\u0440\u0433\u0430\u0435\u0442 <em>(heyat\u0101m... \u0101s\u0101dayati)</em> \u044D\u0442\u0443 [\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E] <em>(asya)</em>, \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044F [\u0435\u0435] \u0431\u0435\u0441\u043F\u043E\u043B\u0435\u0437\u043D\u043E\u0439 \u0438 \u043D\u0435\u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0439 <em>(tucchat\u0101m ni\u1E25s\u0101rat\u0101m... \u0101s\u0101dayati)</em>. [\u041A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F,] \u043E\u043D \u043D\u0435 <em>(na tu)</em> \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 [\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E] <em>(up\u0101deyat\u0101m... \u0101s\u0101dayati iti)</em><sup>1</sup>&quot;|</p><p>\u042D\u0442\u043E\u0442 [\u0432\u0438\u0434 \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0430\u0446\u0438\u0438] <em>(etad ca)</em> \u043D\u0430\u043C <em>(na\u1E25)</em> \u043D\u0435 <em>(na)</em> \u043D\u0440\u0430\u0432\u0438\u0442\u0441\u044F <em>(pratibh\u0101ti)</em>, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043E\u043D \u043D\u0435 \u043E\u0447\u0435\u043D\u044C \u0441\u043E\u0433\u043B\u0430\u0441\u043E\u0432\u044B\u0432\u0430\u0435\u0442\u0441\u044F <em>(na atic\u0101rutv\u0101t)</em> \u0441 \u0430\u0441\u0441\u043E\u0446\u0438\u0430\u0446\u0438\u0435\u0439, \u0438\u043B\u0438 \u0441\u0432\u044F\u0437\u044C\u044E <em>(sa\u1E45gate\u1E25)</em> \u043C\u0435\u0436\u0434\u0443 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F\u043C\u0438 <em>(artha)</em> \u0441\u043B\u043E\u0432 <em>(pada)</em>, \u0438 <em>(ca)</em> \u043F\u043E\u0442\u043E\u043C\u0443, \u0447\u0442\u043E \u0432 \u043A\u0430\u0436\u0434\u043E\u043C <em>(prati)</em> \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435 <em>(s\u016Btram)</em> \u043C\u043E\u0436\u043D\u043E <em>(\u015Bakyatv\u0101t)</em> \u043F\u043E\u043A\u0430\u0437\u0430\u0442\u044C <em>(dar\u015Bayitum)</em> \u0442\u044B\u0441\u044F\u0447\u0438 <em>(sahasra\u015Ba\u1E25)</em> \u0441\u043F\u043E\u0441\u043E\u0431\u043E\u0432 <em>(kramasya)</em> \u0442\u0430\u043A\u0438\u0445 <em>(\u012Bd\u1E5B\u015Ba)</em> \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0439 <em>(vy\u0101khy\u0101)</em>||29||</p><hr><ol><li><p>\u042D\u0442\u0430 \u0447\u0430\u0441\u0442\u044C \u043E\u0447\u0435\u043D\u044C \u043A\u0430\u0432\u0435\u0440\u0437\u043D\u0430\u044F \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u0435\u0435 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0430. \u0412\u043E\u0442 \u043F\u043E\u0447\u0435\u043C\u0443, \u0434\u043B\u044F \u0431\u043B\u0430\u0433\u0430 \u0432\u0441\u0435\u0445 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0445 \u0441\u0442\u0443\u0434\u0435\u043D\u0442\u043E\u0432 (\u0438 \u043C\u043E\u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0442\u043E\u0436\u0435, \u0445\u0435-\u0445\u0435), \u044D\u0442\u0438\u043C \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0435\u043C \u044F \u0441\u0434\u0435\u043B\u0430\u044E \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0430 \u044F\u0441\u043D\u044B\u043C. \u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043C\u043E\u0438\u043C \u043D\u044B\u043D\u0435\u0448\u043D\u0438\u043C \u0437\u043D\u0430\u043D\u0438\u044F\u043C, \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u044B\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u0442\u0430\u043A\u043E\u0432, \u043A\u0430\u043A \u044F \u0435\u0433\u043E \u043D\u0430\u043F\u0438\u0441\u0430\u043B, \u0442.\u0435. &quot;\u0412 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 <em>(tad\u0101 ca)</em>, \u043E\u043D \u043E\u0442\u0432\u0435\u0440\u0433\u0430\u0435\u0442 <em>(heyat\u0101m... \u0101s\u0101dayati)</em> \u044D\u0442\u0443 [\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E] <em>(asya)</em>, \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044F [\u0435\u0435] \u0431\u0435\u0441\u043F\u043E\u043B\u0435\u0437\u043D\u043E\u0439 \u0438 \u043D\u0435\u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0439 <em>(tucchat\u0101m ni\u1E25s\u0101rat\u0101m... \u0101s\u0101dayati)</em>. [\u041A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F,] \u043E\u043D \u043D\u0435 <em>(na tu)</em> \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 [\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E] <em>(up\u0101deyat\u0101m... \u0101s\u0101dayati iti)</em>|&quot;. OK, \u044D\u0442\u043E\u0442 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u043F\u043E\u044F\u0432\u0438\u043B\u0441\u044F \u0434\u043B\u044F \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F \u043F\u043E\u0442\u0440\u0435\u0431\u043D\u043E\u0441\u0442\u0435\u0439 \u0441\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0433\u043E \u0437\u0430\u043F\u0430\u0434\u043D\u043E\u0433\u043E \u0443\u043C\u0430, \u043D\u043E \u043A\u0430\u043A \u0431\u044B\u0442\u044C \u0431\u043E\u043B\u0435\u0435 \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u044B\u043C \u0438 \u043D\u0430\u0447\u0430\u0442\u044C \u0434\u0443\u043C\u0430\u0442\u044C \u043A\u0430\u043A \u0434\u0440\u0435\u0432\u043D\u0438\u0435?: &quot;\u0412 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 <em>(tad\u0101 ca)</em>, \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 <em>(\u0101s\u0101dayati)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u043E\u0442\u0432\u0435\u0440\u0436\u0435\u043D\u0438\u044F <em>(heyat\u0101m)</em>, \u0431\u0435\u0441\u043F\u043E\u043B\u0435\u0437\u043D\u043E\u0441\u0442\u0438 <em>(tucchat\u0101m)</em> [\u0438] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u043D\u0435\u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(ni\u1E25s\u0101rat\u0101m)</em> \u044D\u0442\u043E\u0439 [\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439] <em>(asya)</em>. [\u041A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F,] \u043E\u043D \u043D\u0435 <em>(na tu)</em> \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 <em>(\u0101s\u0101dayati)</em> [\u0435\u0435] \u043F\u0440\u0438\u0435\u043C\u043B\u0435\u043C\u043E\u0441\u0442\u0438 <em>(up\u0101deyat\u0101m... iti)</em>|&quot;. \u0410\u0445, \u044D\u0442\u043E \u0431\u043E\u043B\u0435\u0437\u043D\u0435\u043D\u043D\u043E!</p><p>\u041E\u043A, \u044F \u043F\u043E\u043B\u0430\u0433\u0430\u044E, \u0447\u0442\u043E \u044D\u0442\u0430 \u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0430 \u0444\u0440\u0430\u0437\u044B \u043D\u0430 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0435 \u0438 \u043C\u043E\u0439 \u0441\u043F\u043E\u0441\u043E\u0431 \u0435\u0435 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0430 \u0442\u0435\u043F\u0435\u0440\u044C \u043F\u043E\u043D\u044F\u0442\u0435\u043D \u0441\u0442\u0443\u0434\u0435\u043D\u0442\u0430\u043C.</p></li></ol></div><div class="stanza"><a href="#s3.30" id="s3.30" class="num">3.30</a><div class="sans"><p>\u0905\u0938\u094D\u092F \u091A\u2014</p><blockquote><p><strong>\u0938\u094D\u0935\u0936\u0915\u094D\u0924\u093F\u092A\u094D\u0930\u091A\u092F\u094B\u093D\u0938\u094D\u092F \u0935\u093F\u0936\u094D\u0935\u092E\u094D\u0965\u0969\u0966\u0965</strong></p></blockquote><p>\u092F\u0924\u094B\u093D\u092F\u0902 \u0936\u093F\u0935\u0924\u0941\u0932\u094D\u092F \u0909\u0915\u094D\u0924\u0938\u094D\u0924\u0924\u094B \u092F\u0925\u093E</p><blockquote><p>\u0936\u0915\u094D\u0924\u092F\u094B\u093D\u0938\u094D\u092F \u091C\u0917\u0924\u094D\u0915\u0943\u0924\u094D\u0938\u094D\u0928\u092E\u094D...\u0964</p></blockquote><p>\u0907\u0924\u094D\u092F\u093E\u0926\u094D\u092F\u093E\u092E\u094D\u0928\u093E\u092F\u0926\u0943\u0937\u094D\u0924\u094D\u092F\u093E \u0936\u093F\u0935\u0938\u094D\u092F \u0935\u093F\u0936\u094D\u0935\u0902 \u0938\u094D\u0935\u0936\u0915\u094D\u0924\u093F\u092E\u092F\u0902 \u0924\u0925\u093E\u0938\u094D\u092F\u093E\u092A\u093F \u0938\u094D\u0935\u0938\u094D\u092F\u093E\u0903 \u0938\u0902\u0935\u093F\u0926\u093E\u0924\u094D\u092E\u0928\u0903 \u0936\u0915\u094D\u0924\u0947\u0903 \u092A\u094D\u0930\u091A\u092F\u0903 \u0915\u094D\u0930\u093F\u092F\u093E\u0936\u0915\u094D\u0924\u093F\u0938\u094D\u092B\u0941\u0930\u0923\u0930\u0942\u092A\u094B \u0935\u093F\u0915\u093E\u0938\u094B \u0935\u093F\u0936\u094D\u0935\u092E\u094D\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u092E\u0943\u0924\u094D\u092F\u0941\u091C\u093F\u0924\u093F</p><blockquote><p>\u092F\u0924\u094B \u091C\u094D\u091E\u093E\u0928\u092E\u092F\u094B \u0926\u0947\u0935\u094B \u091C\u094D\u091E\u093E\u0928\u0902 \u091A \u092C\u0939\u0941\u0927\u093E \u0938\u094D\u0925\u093F\u0924\u092E\u094D\u0964<br> \u0928\u093F\u092F\u0928\u094D\u0924\u094D\u0930\u093F\u0924\u093E\u0928\u093E\u0902 \u092C\u0926\u094D\u0927\u093E\u0928\u093E\u0902 \u0924\u094D\u0930\u093E\u0923\u0902 \u0924\u0928\u094D\u0928\u0947\u0924\u094D\u0930\u092E\u0941\u091A\u094D\u092F\u0924\u0947\u0965</p></blockquote><p>\u0915\u093E\u0932\u093F\u0915\u093E\u0915\u094D\u0930\u092E\u0947\u093D\u092A\u093F</p><blockquote><p>\u0924\u0924\u094D\u0924\u0926\u094D\u0930\u0942\u092A\u0924\u092F\u093E \u091C\u094D\u091E\u093E\u0928\u0902 \u092C\u0939\u093F\u0930\u0928\u094D\u0924\u0903 \u092A\u094D\u0930\u0915\u093E\u0936\u0924\u0947\u0964<br> \u091C\u094D\u091E\u093E\u0928\u093E\u0926\u0943\u0924\u0947 \u0928\u093E\u0930\u094D\u0925\u0938\u0924\u094D\u0924\u093E \u091C\u094D\u091E\u093E\u0928\u0930\u0942\u092A\u0902 \u0924\u0924\u094B \u091C\u0917\u0924\u094D\u0965<br> \u0928 \u0939\u093F \u091C\u094D\u091E\u093E\u0928\u093E\u0926\u0943\u0924\u0947 \u092D\u093E\u0935\u093E\u0903 \u0915\u0947\u0928\u091A\u093F\u0926\u094D\u0935\u093F\u0937\u092F\u0940\u0915\u0943\u0924\u093E\u0903\u0964<br> \u091C\u094D\u091E\u093E\u0928\u0902 \u0924\u0926\u093E\u0924\u094D\u092E\u0924\u093E\u0902 \u092F\u093E\u0924\u092E\u0947\u0924\u0938\u094D\u092E\u093E\u0926\u0935\u0938\u0940\u092F\u0924\u0947\u0965<br> \u0905\u0938\u094D\u0924\u093F\u0928\u093E\u0938\u094D\u0924\u093F\u0935\u093F\u092D\u093E\u0917\u0947\u0928 \u0928\u093F\u0937\u0947\u0927\u0935\u093F\u0927\u093F\u092F\u094B\u0917\u0924\u0903\u0964<br> \u091C\u094D\u091E\u093E\u0928\u093E\u0924\u094D\u092E\u0924\u093E \u091C\u094D\u091E\u0947\u092F\u0928\u093F\u0937\u094D\u0920\u093E \u092D\u093E\u0935\u093E\u0928\u093E\u0902 \u092D\u093E\u0935\u0928\u093E\u092C\u0932\u093E\u0924\u094D\u0965<br> \u092F\u0941\u0917\u092A\u0926\u094D\u0935\u0947\u0926\u0928\u093E\u091C\u094D\u091C\u094D\u091E\u093E\u0928\u091C\u094D\u091E\u0947\u092F\u092F\u094B\u0930\u0947\u0915\u0930\u0942\u092A\u0924\u093E\u0964</p></blockquote><p>\u0907\u0924\u093F\u0965\u0969\u0966\u0965</p></div><hr><div class="trans"><p>Asya ca\u2014</p><blockquote><p><strong>Sva\u015Baktipracayo&#39;sya vi\u015Bvam||30||</strong></p></blockquote><p>Yato&#39;ya\u1E41 \u015Bivatulya uktastato yath\u0101</p><blockquote><p>\u015Aaktayo&#39;sya jagatk\u1E5Btsnam...|</p></blockquote><p>ity\u0101dy\u0101mn\u0101yad\u1E5B\u1E63ty\u0101 \u015Bivasya vi\u015Bva\u1E41 sva\u015Baktimaya\u1E41 tath\u0101sy\u0101pi svasy\u0101\u1E25 sa\u1E41vid\u0101tmana\u1E25 \u015Bakte\u1E25 pracaya\u1E25 kriy\u0101\u015Baktisphura\u1E47ar\u016Bpo vik\u0101so vi\u015Bvam| Yadukta\u1E41 \u015Br\u012Bm\u1E5Btyujiti</p><blockquote><p>Yato j\xF1\u0101namayo devo j\xF1\u0101na\u1E41 ca bahudh\u0101 sthitam|<br> Niyantrit\u0101n\u0101\u1E41 baddh\u0101n\u0101\u1E41 tr\u0101\u1E47a\u1E41 tannetramucyate||</p></blockquote><p>K\u0101lik\u0101krame&#39;pi</p><blockquote><p>Tattadr\u016Bpatay\u0101 j\xF1\u0101na\u1E41 bahiranta\u1E25 prak\u0101\u015Bate|<br> J\xF1\u0101n\u0101d\u1E5Bte n\u0101rthasatt\u0101 j\xF1\u0101nar\u016Bpa\u1E41 tato jagat||<br> Na hi j\xF1\u0101n\u0101d\u1E5Bte bh\u0101v\u0101\u1E25 kenacidvi\u1E63ay\u012Bk\u1E5Bt\u0101\u1E25|<br> J\xF1\u0101na\u1E41 tad\u0101tmat\u0101\u1E41 y\u0101tametasm\u0101davas\u012Byate||<br> Astin\u0101stivibh\u0101gena ni\u1E63edhavidhiyogata\u1E25|<br> J\xF1\u0101n\u0101tmat\u0101 j\xF1eyani\u1E63\u1E6Dh\u0101 bh\u0101v\u0101n\u0101\u1E41 bh\u0101van\u0101bal\u0101t||<br> Yugapadvedan\u0101jj\xF1\u0101naj\xF1eyayorekar\u016Bpat\u0101|</p></blockquote><p>iti||30||</p></div><hr><p>\u0418 <em>(ca)</em> \u0434\u043B\u044F \u044D\u0442\u043E\u0433\u043E [Yog\u012B] <em>(asya)</em>\u2014</p><blockquote><p><strong>\u0412\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F <em>(vi\u015Bvam)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435\u043C, \u0438\u043B\u0438 \u0440\u0430\u0437\u0432\u0435\u0440\u0442\u044B\u0432\u0430\u043D\u0438\u0435\u043C <em>(pracaya\u1E25)</em> \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sva... asya)</em> \u0421\u0438\u043B\u044B <em>(\u015Bakti)</em>||30||</strong></p></blockquote><p>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 <em>(yatas)</em> \u043E \u043D\u0435\u043C <em>(ayam)</em> \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(ukta\u1E25)</em>, \u0447\u0442\u043E \u043E\u043D \u043F\u043E\u0434\u043E\u0431\u0435\u043D <em>(tulya\u1E25)</em> \u015Aiva <em>(\u015Biva)</em>, \u0442\u043E <em>(tatas)</em>, \u0442\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u0436\u0435 \u043A\u0430\u043A <em>(yath\u0101)</em> \u0441 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F <em>(d\u1E5B\u1E63ty\u0101)</em> \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u044B\u0445 \u0442\u0435\u043A\u0441\u0442\u043E\u0432 <em>(\u0101mn\u0101ya)</em>, \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F <em>(vi\u015Bvam)</em> \u0428\u0438\u0432\u044B <em>(\u015Bivasya)</em> \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u0430 <em>(mayam)</em> \u0415\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sva)</em> \u015Aakti, \u0438\u043B\u0438 \u0421\u0438\u043B\u043E\u0439 <em>(\u015Bakti)</em>:</p><blockquote><p>&quot;\u0415\u0433\u043E <em>(asya)</em> \u0441\u0438\u043B\u044B <em>(\u015Baktaya\u1E25)</em> [\u2014 \u044D\u0442\u043E] \u0432\u0435\u0441\u044C <em>(k\u1E5Btsnam)</em> \u043C\u0438\u0440 <em>(jagat)</em>, \u0438 \u0442.\u0434. <em>(iti-\u0101di)</em><sup>1</sup>&quot;|</p></blockquote><p>\u043F\u043E\u044D\u0442\u043E\u043C\u0443 <em>(tath\u0101)</em>, \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F <em>(vi\u015Bvam)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0440\u0430\u0437\u0432\u0435\u0440\u0442\u044B\u0432\u0430\u043D\u0438\u0435\u043C <em>(pracaya\u1E25)</em>, [\u0438\u043B\u0438] \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435\u043C <em>(vik\u0101sa\u1E25)</em> \u2014\u0441\u0432\u0435\u0440\u043A\u0430\u043D\u0438\u044F <em>(sphura\u1E47a-r\u016Bpa\u1E25)</em> \u0421\u0438\u043B\u044B <em>(\u015Bakti)</em> \u0414\u0435\u0439\u0441\u0442\u0432\u0438\u044F <em>(kriy\u0101)</em>, [\u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0439 \u043C\u0438\u0440]\u2014 \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(asya api svasy\u0101\u1E25)</em> \u015Aakti <em>(\u015Bakte\u1E25)</em>, \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(\u0101tmana\u1E25)</em> \u2014 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(sa\u1E41vid)</em>|</p><p>\u042D\u0442\u043E <em>(yad)</em> [\u0442\u0430\u043A\u0436\u0435] \u0431\u044B\u043B\u043E \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E <em>(uktam)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C M\u1E5Btyujit --Netratantra-- <em>(\u015Br\u012B-m\u1E5Btyujiti)</em>:</p><blockquote><p>&quot;\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 <em>(yatas)</em> \u0411\u043E\u0433 <em>(deva\u1E25)</em> \u0435\u0441\u0442\u044C \u0412\u044B\u0441\u0448\u0430\u044F \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0432 \u0432\u0438\u0434\u0435 \u0427\u0438\u0441\u0442\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101na-maya\u1E25)</em>, \u0438 <em>(ca)</em> J\xF1\u0101na [\u0438\u043B\u0438 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435] <em>(j\xF1\u0101nam)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(sthitam)</em> \u0432\u043E \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435 \u0444\u043E\u0440\u043C <em>(bahudh\u0101)</em>, [\u0438 \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0411\u043E\u0433 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F] \u0417\u0430\u0449\u0438\u0442\u043D\u0438\u043A\u043E\u043C <em>(tr\u0101\u1E47am)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0445, \u0438\u043B\u0438 \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432 <em>(niyantrit\u0101n\u0101m)</em> \u2014\u0442\u0435\u0445, \u043A\u0442\u043E \u0436\u0438\u0432\u0435\u0442 \u0432 \u0440\u0430\u0431\u0441\u0442\u0432\u0435 <em>(baddh\u0101n\u0101m)</em>\u2014, \u0442\u043E <em>(tad)</em> \u041E\u043D, \u043A\u0430\u043A \u0433\u043E\u0432\u043E\u0440\u044F\u0442, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(ucyate)</em> Netra <em>(netram... iti)</em><sup>2</sup>&quot;||<br> [\u0421\u043C. IX, 12 \u0432 Netratantra]</p></blockquote><p>\u0438 \u0442\u0430\u043A\u0436\u0435 <em>(api)</em> \u0432 K\u0101lik\u0101krama <em>(k\u0101lik\u0101krame)</em>:</p><blockquote><p>&quot;\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101na)</em> \u0441\u0438\u044F\u0435\u0442 --\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u043C-- <em>(prak\u0101\u015Bate)</em> \u0432\u043D\u0443\u0442\u0440\u0438 <em>(antar)</em> [\u0438] \u0441\u043D\u0430\u0440\u0443\u0436\u0438 <em>(bahis)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u043C\u0438 \u0441\u043F\u043E\u0441\u043E\u0431\u0430\u043C\u0438 <em>(tad-tad-r\u016Bpatay\u0101)</em> --\u0442.\u0435. \u0432\u043D\u0443\u0442\u0440\u0438 - \u043A\u0430\u043A \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435, \u0441\u043D\u0430\u0440\u0443\u0436\u0438 - \u043A\u0430\u043A \u0433\u043E\u0440\u0448\u043E\u043A, \u0438 \u0442.\u043F.--. \u041D\u0435\u0442 <em>(na)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(satt\u0101)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 <em>(artha)</em> \u0431\u0435\u0437 <em>(\u1E5Bte)</em> \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101n\u0101t)</em>. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(tatas)</em>, \u043C\u0438\u0440 <em>(jagat)</em> [\u2014 \u044D\u0442\u043E] \u0444\u043E\u0440\u043C\u0430 <em>(r\u016Bpam)</em> \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101na)</em>. \u0411\u0435\u0437 <em>(\u1E5Bte)</em> \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101n\u0101t)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u044B <em>(bh\u0101v\u0101\u1E25)</em> \u043D\u0435 <em>(na hi)</em> \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C\u044B <em>(vi\u1E63ay\u012Bk\u1E5Bt\u0101\u1E25)</em> \u043D\u0438 \u043A\u0435\u043C <em>(kenacid)</em>. \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101nam)</em> \u0441\u0442\u0430\u043B\u043E <em>(y\u0101tam)</em> \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(\u0101tmat\u0101m)</em> \u0442\u0435\u0445 [\u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432] <em>(tad)</em>, [\u0438] \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0435\u0433\u043E <em>(etasm\u0101t)</em> [\u043A\u0430\u0436\u0434\u044B\u0439 \u0438\u0437 \u043D\u0438\u0445] \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u0435\u0442\u0441\u044F \u0438 \u0447\u0435\u0442\u043A\u043E \u0440\u0430\u0437\u043B\u0438\u0447\u0430\u0435\u0442\u0441\u044F <em>(avas\u012Byate)</em>. \u0427\u0435\u0440\u0435\u0437 \u043F\u0440\u0438\u043C\u0435\u043D\u0435\u043D\u0438\u0435 <em>(yogatas)</em> \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u044F \u0438 \u043E\u0442\u0440\u0438\u0446\u0430\u043D\u0438\u044F <em>(ni\u1E63edha-vidhi)</em>, \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435 --\u0431\u0443\u043A\u0432. \u0441/\u0447\u0435\u0440\u0435\u0437 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435-- <em>(vibh\u0101gena)</em> \u043F\u043E\u0437\u0438\u0442\u0438\u0432\u043D\u044B\u0445 \u0438 \u043D\u0435\u0433\u0430\u0442\u0438\u0432\u043D\u044B\u0445 bh\u0101va-s, \u0438\u043B\u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 --\u0442.\u0435. \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u0445 \u0438 \u043D\u0435\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u0445-- <em>(asti-na-asti)</em>. \u041E\u0431\u044A\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u044C --\u0442.\u0435. \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0431\u044B\u0442\u0438\u044F \u043E\u0431\u044A\u0435\u043A\u0442\u0430, \u0438\u043B\u0438 j\xF1eya-- <em>(j\xF1eya-ni\u1E63\u1E6Dh\u0101)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 <em>(bh\u0101v\u0101n\u0101m)</em> [\u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F] \u043A\u0430\u043A \u043E\u0431\u043B\u0430\u0434\u0430\u044E\u0449\u0430\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C \u043F\u043E \u0441\u0432\u043E\u0435\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438 <em>(j\xF1\u0101na-\u0101tmat\u0101)</em> \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0441\u0438\u043B\u0435 <em>(bal\u0101t)</em> bh\u0101van\u0101, \u0438\u043B\u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0441\u0432\u043E\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(bh\u0101van\u0101)</em>. \u0412 \u0441\u043B\u0443\u0447\u0430\u0435 \u0437\u043D\u0430\u043D\u0438\u044F \u0438 \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0433\u043E <em>(j\xF1\u0101na-j\xF1eyayo\u1E25)</em>, \u043E\u043D\u0438 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043E\u0434\u043D\u0438\u043C \u0438 \u0442\u0435\u043C \u0436\u0435 --\u0431\u0443\u043A\u0432. [\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F] \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u043E\u0439-- <em>(eka-r\u016Bpat\u0101)</em> \u0438\u0437-\u0437\u0430 \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0441\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u043D\u0438\u044F <em>(yugapad-vedan\u0101t... iti)</em> --\u0441\u043B\u043E\u0432\u043E\u043C, \u0437\u043D\u0430\u043D\u0438\u0435 \u0438 \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0435 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0442\u0441\u044F \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E, \u0442\u0430\u043A \u043A\u0430\u043A \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u043E\u0442\u0441\u0442\u0443\u0441\u0442\u0432\u0438\u044F \u043E\u0434\u043D\u043E\u0433\u043E, \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0438 \u0434\u0440\u0443\u0433\u043E\u0433\u043E--&quot;|</p></blockquote><p>||30||</p><hr><ol><li><p>\u042D\u0442\u043E &quot;\u0438 \u0442.\u0434.&quot; \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u043C\u043D\u043E\u0433\u043E\u0442\u043E\u0447\u0438\u0435.</p></li><li><p>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u0430 \u0441\u0442\u0440\u043E\u0444\u0430 \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442 \u043E\u0447\u0435\u043D\u044C \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0435 \u0437\u043D\u0430\u043D\u0438\u044F, \u044F \u043F\u0440\u043E\u0446\u0438\u0442\u0438\u0440\u0443\u044E \u0432\u0435\u0441\u044C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 K\u1E63emar\u0101ja \u043D\u0430\u043F\u0438\u0441\u0430\u043B \u043D\u0430 \u043D\u0435\u0433\u043E \u0441\u0432\u043E\u0435\u0439 Netroddyota. \u041F\u043E\u043C\u0438\u043C\u043E \u044D\u0442\u043E\u0433\u043E, \u0432\u044B \u043F\u043E\u0439\u043C\u0435\u0442\u0435, \u043F\u043E\u0447\u0435\u043C\u0443 \u044F \u043F\u0435\u0440\u0435\u0432\u0435\u043B \u044D\u0442\u0443 \u0441\u0442\u0440\u043E\u0444\u0443 \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u043A\u0430\u043A \u044F \u044D\u0442\u043E \u0441\u0434\u0435\u043B\u0430\u043B: &quot;\u0926\u0947\u0935\u0903 \u092A\u0930\u092E\u0947\u0936\u094D\u0935\u0930\u094B \u091C\u094D\u091E\u093E\u0928\u092E\u092F\u0936\u094D\u091A\u093F\u0928\u094D\u092E\u093E\u0924\u094D\u0930\u092A\u0930\u092E\u093E\u0930\u094D\u0925\u0903\u0964 \u0924\u091A\u094D\u091A \u091C\u094D\u091E\u093E\u0928\u0902 \u092C\u0939\u0941\u0927\u0947\u0924\u093F \u0938\u094D\u0935\u093E\u0924\u0928\u094D\u0924\u094D\u0930\u094D\u092F\u093E\u0924\u094D\u0938\u0919\u094D\u0915\u094B\u091A\u092E\u093E\u092D\u093E\u0938\u094D\u092F \u0928\u093E\u0928\u093E\u0924\u094D\u0935\u092E\u093E\u0936\u094D\u0930\u093F\u0924\u094D\u092F \u0938\u094D\u0925\u093F\u0924\u092E\u094D\u0964 \u0905\u0924\u0936\u094D\u091A \u0938\u0919\u094D\u0915\u094B\u091A\u093E\u092D\u093E\u0938\u092D\u093E\u091C\u094B \u092F\u0947 \u0928\u093F\u0917\u0942\u0939\u093F\u0924\u0938\u094D\u0935\u0930\u0942\u092A\u0924\u092F\u093E \u0928\u093F\u092F\u0928\u094D\u0924\u094D\u0930\u093F\u0924\u093E \u0906\u092D\u093E\u0938\u093F\u0924\u093E \u0926\u0947\u0935\u0947\u0928 \u0924\u0924 \u090F\u0935 \u092C\u0926\u094D\u0927\u093E\u0938\u094D\u0924\u0947\u0937\u093E\u0902 \u0928\u093E\u0928\u093E\u0926\u0930\u094D\u0936\u0928\u094B\u092A\u093E\u0938\u093E\u092D\u093F\u0903 \u0938\u094D\u0935\u0938\u094D\u0935\u0930\u0942\u092A\u092A\u094D\u0930\u0925\u093E\u0939\u0947\u0924\u0941\u0924\u092F\u093E \u092F\u0924\u094B \u0926\u0947\u0935\u0938\u094D\u0924\u094D\u0930\u093E\u0923\u0902 \u0924\u0938\u094D\u092E\u093E\u0928\u094D\u0928\u093F\u0930\u0941\u0915\u094D\u0924\u0926\u0943\u0936\u093E \u0928\u0947\u0924\u094D\u0930\u092E\u0941\u091A\u094D\u092F\u0924\u0947 \u0928 \u0924\u0941 \u091A\u0915\u094D\u0937\u0941\u0930\u094D\u0917\u094B\u0932\u0915\u0924\u092F\u093E\u0965\u0967\u0968\u0965 &quot; - &quot;Deva\u1E25 parame\u015Bvaro j\xF1\u0101namaya\u015Bcinm\u0101traparam\u0101rtha\u1E25| Tacca j\xF1\u0101na\u1E41 bahudheti sv\u0101tantry\u0101tsa\u1E45kocam\u0101bh\u0101sya n\u0101n\u0101tvam\u0101\u015Britya sthitam| Ata\u015Bca sa\u1E45koc\u0101bh\u0101sabh\u0101jo ye nig\u016Bhitasvar\u016Bpatay\u0101 niyantrit\u0101 \u0101bh\u0101sit\u0101 devena tata eva baddh\u0101ste\u1E63\u0101\u1E41 n\u0101n\u0101dar\u015Banop\u0101s\u0101bhi\u1E25 svasvar\u016Bpaprath\u0101hetutay\u0101 yato devastr\u0101\u1E47a\u1E41 tasm\u0101nniruktad\u1E5B\u015B\u0101 netramucyate na tu cak\u1E63urgolakatay\u0101||12||&quot; - &quot;\u0411\u043E\u0433, \u0412\u044B\u0441\u0448\u0438\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F &#39;j\xF1\u0101namaya&#39; --\u0431\u0443\u043A\u0432. \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u044B\u0439 \u0437\u043D\u0430\u043D\u0438\u044F\u043C\u0438--, \u0442.\u0435. \u0412\u044B\u0441\u0448\u0435\u0439 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E \u0432 \u0444\u043E\u0440\u043C\u0435 \u0447\u0438\u0441\u0442\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F. \u042D\u0442\u0430 J\xF1\u0101na [\u0438\u043B\u0438 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435], \u043F\u0440\u0438\u043D\u044F\u0432 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C [\u0438] \u043F\u0440\u043E\u044F\u0432\u0438\u0432 \u0441\u0436\u0430\u0442\u0438\u0435 \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C [\u0415\u0433\u043E] \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0421\u0432\u043E\u0431\u043E\u0434\u044B, \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 &#39;\u0432\u043E \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435 \u0444\u043E\u0440\u043C&#39;. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u0442\u0435 \u043A\u0442\u043E \u0443\u0447\u0430\u0441\u0442\u0432\u0443\u0435\u0442 \u0432 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0438 \u0441\u0436\u0430\u0442\u0438\u044F, \u0431\u0443\u0434\u0443\u0447\u0438 \u0438\u0445 \u0441\u043A\u0440\u044B\u0442\u043E\u0439 [\u0438\u043B\u0438 \u0437\u0430\u043C\u0430\u0441\u043A\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0439] \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0411\u043E\u0433\u043E\u043C \u043A\u0430\u043A \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0435 [\u0438\u043B\u0438 \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u044B\u0435] \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430. \u0418 \u043F\u043E \u044D\u0442\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435, \u043E\u043D\u0438 \u043D\u0430\u0445\u043E\u0434\u044F\u0442\u0441\u044F \u0432 \u0440\u0430\u0431\u0441\u0442\u0432\u0435. [\u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435,] \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0438\u0445 \u043F\u043E\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u044E \u0438 \u043F\u043E\u0447\u0442\u0435\u043D\u0438\u044E, \u043F\u0440\u0435\u0434\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u043C\u0438 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u043C\u0438 \u0444\u0438\u043B\u043E\u0441\u043E\u0444\u0441\u043A\u0438\u043C\u0438 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u043C\u0438 \u0438 \u0443\u0447\u0435\u043D\u0438\u044F\u043C\u0438, \u0413\u043E\u0441\u043F\u043E\u0434\u044C [\u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F \u0432] \u0438\u0445 &#39;Tr\u0101\u1E47a&#39;, \u0438\u043B\u0438 \u0417\u0430\u0449\u0438\u0442\u043D\u0438\u043A\u0430, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u043E\u043D \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u044F \u0438\u0445 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B --\u0442.\u0435. \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u044D\u0442\u0438\u0445 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432 \u043F\u0435\u0440\u0435\u0441\u0442\u0430\u0435\u0442 \u0431\u044B\u0442\u044C \u0441\u043A\u0440\u044B\u0442\u043E\u0439--. \u0421 \u044D\u0442\u043E\u0439 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F, \u0441 \u044D\u0442\u0438\u043C\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0442\u043E\u0447\u043A\u0435 \u0437\u0440\u0435\u043D\u0438\u044F, \u041E\u043D \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F &#39;Netra&#39; --\u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u0442\u0435\u0440\u043C\u0438\u043D Netra \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0430\u0431\u0440\u0435\u0432\u0435\u0430\u0442\u0443\u0440\u043E\u0439 \u043E\u0442 &#39;niyantrit\u0101n\u0101\u1E41 tr\u0101\u1E47am&#39;, \u0438\u043B\u0438 &#39;\u0437\u0430\u0449\u0438\u0442\u043D\u0438\u043A \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0445/\u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432&#39;--. [\u041E\u043D] \u043D\u0435 [\u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F &#39;Netra&#39;] \u0432 \u0441\u043C\u044B\u0441\u043B\u0435 &#39;\u0433\u043B\u0430\u0437\u043D\u043E\u0433\u043E \u044F\u0431\u043B\u043E\u043A\u0430&#39; --\u0442\u0430\u043A \u043A\u0430\u043A \u043E\u0431\u044B\u0447\u043D\u044B\u043C \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435\u043C \u0442\u0435\u0440\u043C\u0438\u043D\u0430 &quot;netra&quot; \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F &quot;\u0433\u043B\u0430\u0437&quot;--||12||&quot;.</p><p>\u041E\u0447\u0435\u043D\u044C \u0445\u043E\u0440\u043E\u0448\u043E! \u0418 \u043F\u043E\u043C\u043D\u0438\u0442\u0435, \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E \u043E\u0442 \u0442\u043E\u0433\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0435\u0441\u044C \u043B\u0438 \u0432\u044B \u0442\u0435\u043C, \u0447\u044C\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u0441\u043E\u043A\u0440\u044B\u0442\u0430 \u0438\u043B\u0438 \u0440\u0430\u0441\u043A\u0440\u044B\u0442\u0430 (\u043B\u0438\u0431\u043E \u0441\u043C\u0435\u0448\u0430\u043D\u0430), \u0412\u044B\u0441\u0448\u0435\u0439 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E \u0432\u0441\u0435\u0433\u0434\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u0430\u0448\u0435 \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0435 \u0412\u044B\u0441\u0448\u0435\u0435 \u042F. \u0415\u0441\u043B\u0438 \u0432\u044B \u0447\u0438\u0442\u0430\u0435\u0442\u0435 \u044D\u0442\u043E \u0421\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0435 \u041F\u0438\u0441\u0430\u043D\u0438\u0435 \u0438 \u0434\u0443\u043C\u0430\u0435\u0442\u0435, \u0447\u0442\u043E \u0430\u0432\u0442\u043E\u0440 \u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u043E &quot;\u0434\u0440\u0443\u0433\u043E\u043C&quot; \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0435, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0434\u043E\u0441\u0442\u0438\u0433 \u0442\u0430\u043A\u043E\u0433\u043E \u0432\u044B\u0441\u043E\u043A\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0432\u044B \u043E\u0448\u0438\u0431\u0430\u0435\u0442\u0435\u0441\u044C \u0438 \u0442\u043E\u043B\u044C\u043A\u043E \u043D\u0430\u043A\u0430\u043F\u043B\u0438\u0432\u0430\u0435\u0442\u0435 \u043A\u043D\u0438\u0436\u043D\u043E\u0435 \u0437\u043D\u0430\u043D\u0438\u0435. \u0415\u0441\u043B\u0438 \u0432\u044B \u043D\u0435 \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442\u0435 \u0441\u0432\u043E\u044E \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u0447\u0442\u0435\u043D\u0438\u044F, tata\u1E25 kim (\u0447\u0442\u043E \u0442\u043E\u0433\u0434\u0430?). \u0418\u0442\u0430\u043A, \u043F\u0440\u0430\u0432\u0434\u0430 \u0437\u0430\u043A\u043B\u044E\u0447\u0430\u0435\u0442\u0441\u044F \u0432 \u0442\u043E\u043C, \u0447\u0442\u043E \u044D\u0442\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u0435 \u043A\u0430\u0441\u0430\u0435\u0442\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u0442\u0435\u0431\u044F \u043E\u0434\u043D\u043E\u0433\u043E! \u0412\u0441\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u0440\u0430\u0441\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u0422\u0432\u043E\u044E \u0438\u0441\u0442\u043E\u0440\u0438\u044E, \u0434\u043E\u0440\u043E\u0433\u043E\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C!</p></li></ol></div>',2),o=[r];function p(s,u,y,n,h,v){return m(),e("div",null,o)}var c=a(i,[["render",p]]);export{k as __pageData,c as default};
